property.embedded_functions:

#include "mmt_lib.h"
void on_load() {
  // Initialize counters and thresholds here
}
void on_unload() {
  // Reset or save state here
}

mmt_rule_satisfied_callback em_on_rule_satisfied = NULL;
int64_t ue_session_churn_threshold = 50; // Set threshold to 50 sessions per second as an example

void on_rule_satisfied(const rule_t *rule, int verdict, uint64_t timestamp, uint64_t counter, const mmt_array_t *trace) {
  if (verdict == DETECTED) {
    int64_t current_session_count = get_ue_session_count(trace); // Assume a function to count sessions from trace
    if (current_session_count > ue_session_churn_threshold) {
      em_on_rule_satisfied(rule, verdict, timestamp, counter, trace);
    }
  }
}

void set_churn_threshold(int64_t threshold) {
  ue_session_churn_threshold = threshold;
}
